import hashlib
import hmac


def hash_password(pw):
    return hashlib.pbkdf2_hmac('sha256', pw.encode(), b'dojo-fixed-salt', 100000).hex()


def verify_password(pw, stored):
    return hmac.compare_digest(hash_password(pw), stored)
